#include<bits/stdc++.h>
using namespace std;
int n;
char a[4][200010];
int lallnow[200010],rallnow[200010];
int lallmax[200010],rallmax[200010];
bool flagall[200010],flaglr[200010];
bool flagl[200010],flagr[200010];
int A[200010],B[200010];
int vall[200010],valr[200010],nxt[200010];
int maxval[200010];
int main()
{
	scanf("%d%s%s%s",&n,a[1]+1,a[2]+1,a[3]+1);
	for(int i=1;i<=n;i++)
	{
		if(a[1][i]=='.'&&a[2][i]=='.'&&a[3][i]=='.')
		{
			flagall[i]=true;
		}
		if(a[1][i]=='.'&&a[3][i]=='.')
		{
			flaglr[i]=true;
		}
		if(flagall[i])
		{
			lallnow[i]=lallnow[i-1]+1;
		}
		else
		{
			lallnow[i]=0;
		}
		lallmax[i]=max(lallmax[i-1],lallnow[i]);
	}
	for(int i=n;i>=1;i--)
	{
		if(flagall[i])
		{
			rallnow[i]=rallnow[i+1]+1;
		}
		else
		{
			rallnow[i]=0;
		}
		rallmax[i]=max(rallmax[i+1],rallnow[i]);
	}
	int ans=-1;
	for(int i=1;i<=n;i++)
	{
		while(i<=n&&!flaglr[i])
		{
			i++;
		}
		if(i>n)
		{
			break;
		}
		int j=i;
		while(j+1<=n&&flaglr[j+1])
		{
			j++;
		}
		vector<int> v;
		for(int k=i;k<=j;k++)
		{
			if(flagall[k])
			{
				v.push_back(k);
			}
		}
		int m=v.size();
		if(m<2||v[m-1]-v[0]<2)
		{
			i=j;
			continue;
		}
		for(int k=0;k<m;k++)
		{
			int l=v[k]-2,r=v[k]+2;
			int L=(l>=1?lallmax[l]:0);
			int R=(r<=n?rallmax[r]:0);
			A[k]=L+v[k];
			B[k]=v[k]-R+1;
			flagl[k]=(L>=1);
			flagr[k]=(R>=1);
			vall[k]=L*3-v[k]*2;
			valr[k]=R*3+v[k]*2;
			nxt[k]=-1;
			maxval[k]=-1e9;
		}
		for(int k=0;k<m;k++)
		{
			if(k>0)
			{
				maxval[k]=maxval[k-1];
			}
			if(flagl[k])
			{
				maxval[k]=max(maxval[k],vall[k]);
			}
		}
		int lst=-1;
		for(int k=m-1;k>=0;k--)
		{
			if(flagl[k])
			{
				lst=k;
			}
			nxt[k]=lst;
		}
		for(int k=1;k<m;k++)
		{
			if(!flagr[k])
			{
				continue;
			}
			int l=0,r=k-1,best1=-1,best2=-1;
			while(l<=r)
			{
				int mid=(l+r)>>1;
				if(A[mid]<=B[k])
				{
					best1=mid;
					l=mid+1;
				}
				else
				{
					r=mid-1;
				}
			}
			l=0,r=k-1;
			while(l<=r)
			{
				int mid=(l+r)>>1;
				if(v[k]-v[mid]>=2)
				{
					best2=mid;
					l=mid+1;
				}
				else
				{
					r=mid-1;
				}
			}
			int now=min({best1,best2,k-1});
			if(now>=0)
			{
				ans=max(ans,maxval[now]+valr[k]+4);
			}
			now=max(0,best1+1);
			if(now<k)
			{
				int tmp=nxt[now];
				if(tmp!=-1&&tmp<=min(k-1,best2))
				{
					ans=max(ans,5*v[k]-5*v[tmp]+7);
				}
			}
		}
		i=j;
	}
	printf("%d",ans);
	return 0;
}
